// =============================================================
// NODO CODE: FORMATEAR ERROR PARA TELEGRAM
// Este workflow se ejecuta automáticamente cuando falla cualquier
// nodo del workflow principal "Agente WhatsApp PoC"
// =============================================================

const execution = $input.first().json.execution || {};
const workflow = $input.first().json.workflow || {};

// Obtener información del error
const errorMessage = execution.error?.message || 'Error desconocido';
const errorNode = execution.error?.node?.name || 'Nodo desconocido';
const workflowName = workflow.name || 'Workflow desconocido';
const executionId = execution.id || 'N/A';

// Intentar extraer el número de celular del contexto de ejecución
let celular = 'No disponible';
try {
  const data = execution.data?.resultData?.runData;
  if (data) {
    // Buscar en Set Fields
    if (data['Set Fields']) {
      celular = data['Set Fields'][0]?.data?.main?.[0]?.[0]?.json?.celular || celular;
    }
    // Buscar en Webhook Trigger como fallback
    if (celular === 'No disponible' && data['Webhook Trigger']) {
      const webhookData = data['Webhook Trigger'][0]?.data?.main?.[0]?.[0]?.json;
      celular = webhookData?.body?.data?.key?.remoteJid?.replace('@s.whatsapp.net', '') || celular;
    }
  }
} catch (e) {
  celular = 'Error extrayendo número';
}

// Formatear mensaje para Telegram
const mensaje = `🚨 *ERROR EN WORKFLOW*

*Workflow:* ${workflowName}
*Nodo que falló:* ${errorNode}
*Error:* ${errorMessage.substring(0, 500)}
*Contacto:* ${celular}
*Execution ID:* ${executionId}
*Timestamp:* ${new Date().toISOString()}

_Revisar en n8n → Executions para más detalles_`;

return [{
  json: {
    mensaje: mensaje
  }
}];
